"use server";

import { revalidatePath } from "next/cache";
import { createClient } from "@/lib/supabase/server";
import { applyParticipationSchema } from "@/lib/validations/participation";
import { ActionResult } from "@/types/action";

export async function applyParticipation(formData: FormData): Promise<ActionResult> {
  const supabase = await createClient();
  const { data: { user }, error: authError } = await supabase.auth.getUser();

  if (authError || !user) {
    return { success: false, error: "로그인이 필요합니다." };
  }

  const rawData = {
    eventId: formData.get("eventId") as string,
    message: formData.get("message") as string | undefined,
  };

  const validated = applyParticipationSchema.safeParse(rawData);
  if (!validated.success) {
    return { success: false, error: validated.error.errors[0].message };
  }

  const { eventId, message } = validated.data;

  const { error } = await supabase.from("participations").insert({
    event_id: eventId,
    user_id: user.id,
    message: message || null,
    status: "pending",
  });

  if (error) {
    if (error.code === "23505") { // UNIQUE 제약 위반
      return { success: false, error: "이미 참여 신청하셨습니다." };
    }
    return { success: false, error: error.message };
  }

  revalidatePath(`/events/${eventId}`);
  return { success: true };
}
```

