export async function approveParticipation(formData: FormData): Promise<ActionResult> {
  const supabase = await createClient();
  const { data: { user }, error: authError } = await supabase.auth.getUser();

  if (authError || !user) {
    return { success: false, error: "로그인이 필요합니다." };
  }

  const rawData = {
    participationId: formData.get("participationId") as string,
    eventId: formData.get("eventId") as string,
    status: "approved" as const,
  };

  const validated = updateParticipationStatusSchema.safeParse(rawData);
  if (!validated.success) {
    return { success: false, error: validated.error.errors[0].message };
  }

  // 주최자 권한 검증
  const { data: event } = await supabase
    .from("events")
    .select("host_id")
    .eq("id", validated.data.eventId)
    .single();

  if (!event || event.host_id !== user.id) {
    return { success: false, error: "권한이 없습니다." };
  }

  const { error } = await supabase.rpc("approve_participation", {
    p_participation_id: validated.data.participationId,
    p_event_id: validated.data.eventId,
  });

  if (error) {
    if (error.message.includes("max_participants_exceeded")) {
      return { success: false, error: "최대 참여 인원을 초과했습니다." };
    }
    return { success: false, error: error.message };
  }

  revalidatePath(`/events/${validated.data.eventId}/participants`);
  return { success: true };
}
```

