export async function cancelParticipation(formData: FormData): Promise<ActionResult> {
  const supabase = await createClient();
  const { data: { user }, error: authError } = await supabase.auth.getUser();

  if (authError || !user) {
    return { success: false, error: "로그인이 필요합니다." };
  }

  const participationId = formData.get("participationId") as string;
  const eventId = formData.get("eventId") as string;

  // 본인 + pending 상태 검증
  const { data: participation } = await supabase
    .from("participations")
    .select("user_id, status, event_id")
    .eq("id", participationId)
    .single();

  if (!participation) {
    return { success: false, error: "참여 신청을 찾을 수 없습니다." };
  }

  if (participation.user_id !== user.id) {
    return { success: false, error: "권한이 없습니다." };
  }

  if (participation.status !== "pending") {
    return { success: false, error: "대기 중인 신청만 취소할 수 있습니다." };
  }

  const { error } = await supabase
    .from("participations")
    .delete()
    .eq("id", participationId);

  if (error) return { success: false, error: error.message };

  revalidatePath(`/events/${eventId}`);
  return { success: true };
}
