"use server";

import { revalidatePath } from "next/cache";
import { createClient } from "@/lib/supabase/server";
import { createPostSchema } from "@/lib/validations/post";
import { ActionResult } from "@/types/action";
import type { SupabaseClient } from "@supabase/supabase-js";

async function isEventHost(
  supabase: SupabaseClient,
  eventId: string,
  userId: string
): Promise<boolean> {
  const { data } = await supabase
    .from("events")
    .select("host_id")
    .eq("id", eventId)
    .single();
  return data?.host_id === userId;
}

async function isApprovedParticipant(
  supabase: SupabaseClient,
  eventId: string,
  userId: string
): Promise<boolean> {
  const { data } = await supabase
    .from("participations")
    .select("id")
    .eq("event_id", eventId)
    .eq("user_id", userId)
    .eq("status", "approved")
    .single();
  return !!data;
}
```

**createPost 구현:**
```typescript
export async function createPost(formData: FormData): Promise<ActionResult> {
  const supabase = await createClient();
  const { data: { user }, error: authError } = await supabase.auth.getUser();

  if (authError || !user) {
    return { success: false, error: "로그인이 필요합니다." };
  }

  const rawData = {
    eventId: formData.get("eventId") as string,
    type: formData.get("type") as string,
    content: formData.get("content") as string,
  };

  const validated = createPostSchema.safeParse(rawData);
  if (!validated.success) {
    return { success: false, error: validated.error.errors[0].message };
  }

  const { eventId, type, content } = validated.data;
  const host = await isEventHost(supabase, eventId, user.id);

  if (type === "notice" && !host) {
    return { success: false, error: "공지는 주최자만 작성할 수 있습니다." };
  }

  if (type === "comment" && !host) {
    const approved = await isApprovedParticipant(supabase, eventId, user.id);
    if (!approved) {
      return { success: false, error: "승인된 참여자만 댓글을 작성할 수 있습니다." };
    }
  }

  const { error } = await supabase.from("posts").insert({
    event_id: eventId,
    author_id: user.id,
    type,
    content,
  });

  if (error) return { success: false, error: error.message };

  revalidatePath(`/events/${eventId}/posts`);
  return { success: true };
}
```

