import { getParticipations } from "@/actions/participations";
import { getEvent } from "@/actions/events";
import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import { ParticipantList } from "@/components/shared/participant-list";

export default async function ParticipantsPage({
  params,
  searchParams,
}: {
  params: Promise<{ eventId: string }>;
  searchParams: Promise<{ status?: string }>;
}) {
  const { eventId } = await params;
  const { status } = await searchParams;

  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();

  const event = await getEvent(eventId);

  // 주최자가 아닌 경우 리다이렉트
  if (!user || event.host_id !== user.id) {
    redirect(`/events/${eventId}`);
  }

  const participations = await getParticipations(eventId, status);
  const approvedCount = participations.filter(p => p.status === "approved").length;

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold">참여자 관리</h2>
        <p className="text-sm text-muted-foreground">
          {approvedCount} / {event.max_participants ?? "무제한"} 명 승인
